#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=500005;
const ll inf=0x3f3f3f3f;
int n,m,ans,dp[N];
vector<int> g[N];
void dfs(int u,int f)
{
	if(g[u].size()==1)
	{
		dp[u]=1;
		ans=max(ans,1);
		return ;
	}
	if(g[u].size()==2)
	{
        int v;
        if(g[u][0]==f) v=g[u][1];
        else v=g[u][0];
		dp[u]=1+dp[v];
		ans=max(ans,dp[u]);
	}
	int mx=0;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		dfs(v,u);
		int t=dp[v];
		if(dp[u]<t)
		{
			mx=dp[u];
			dp[u]=t;
		}
		else
		{ 
			mx=max(mx,t);
		}

	}
	ans=max(ans,mx+dp[u]+(int)g[u].size()-2+(f!=0));
	dp[u]+=(g[u].size()-1);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0); 
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
    g[1].push_back(0);
	dfs(1,0);
	cout<<ans;
	return 0;
}
